var e=[{id:`L5_1`,type:`dialog`,speaker:`HANNA_NPC_NULL_ARMED`,text:{KOREA:`굉장하네요. 저 작은 무기에 침식체들이 맥도 못 추고 있어요.`,JPN:`すごいですね。あの小さな武器に侵食体は為す術もないみたいです。`,ENG:`Incredible. The C.O.s don’t stand a chance against that small weapon.`,TWN:`好厲害，那個不起眼的小武器，竟然可以讓侵蝕體毫無招架之力。`},stage:{bg:`NOMAD_BORDER`,slots:{L:null,C:{char_id:`HANNA_NPC_NULL_ARMED`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`VIVIEN_OPR_NULL_NULL`,text:{KOREA:`한나 씨, 뒤에!`,JPN:`ハンナさん、後ろ！`,ENG:`Miss Anderson, behind you!`,TWN:`漢娜，小心後面！`},stage:{bg:`NOMAD_BORDER`,slots:{L:null,C:{char_id:`VIVIEN_OPR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`HANNA_NPC_NULL_ARMED`,text:{KOREA:`꺄앗!`,JPN:`きゃあっ！`,ENG:`Kyaah!`,TWN:`哇啊！`},stage:{bg:`NOMAD_BORDER`,slots:{L:null,C:{char_id:`HANNA_NPC_NULL_ARMED`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`이걸로 급한 불은 껐군요. 괜찮으십니까?`,JPN:`これで差し迫った問題は解決しましたね。お怪我はありませんか？`,ENG:`I guess the most urgent problem's been dealt with. Are you okay?`,TWN:`幸好這個來得及派上用場，你還好嗎？`},stage:{bg:`NOMAD_BORDER`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`HANNA_NPC_NULL_ARMED`,text:{KOREA:`하아, 감사합니다. 정신이 없어서 뒤에서 오는 줄도 몰랐어요.`,JPN:`はあ、ありがとうございます。焦っていて後ろから来てるのも気づきませんでした。`,ENG:`*Sigh* Thank you. I didn't even know one was coming from behind me.`,TWN:`呼，謝謝你，我都沒注意到它們從後面撲上來。`},stage:{bg:`NOMAD_BORDER`,slots:{L:null,C:{char_id:`HANNA_NPC_NULL_ARMED`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`HANNA_NPC_NULL_ARMED`,text:{KOREA:`뭐죠? 지진인가?`,JPN:`何でしょう？　地震かな？`,ENG:`Huh? An earthquake?`,TWN:`怎麼回事？是地震嗎？`},stage:{bg:`NOMAD_BORDER`,slots:{L:null,C:{char_id:`HANNA_NPC_NULL_ARMED`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`침식체입니다! 거기서 피하세요!`,JPN:`侵食体です！　避けてください！`,ENG:`It's a C.O.! Get out of the way!`,TWN:`是侵蝕體！快跑！`},stage:{bg:`NOMAD_BORDER`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`HANNA_NPC_NULL_ARMED`,text:{KOREA:`꺄아아아! 뭐가 저렇게 커요? 이러다가 깔리겠어요!`,JPN:`きゃあああ！　なんて大きさ！？　このままじゃ下敷きになっちゃいます！`,ENG:`KYAAAH! Why's it so big?! We're gonna get crushed!!`,TWN:`呃啊啊啊！怎麼塊頭這麼大？會被壓扁啦！`},stage:{bg:`NOMAD_BORDER`,slots:{L:null,C:null,R:{char_id:`HANNA_NPC_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`VIVIEN_OPR_NULL_NULL`,text:{KOREA:`큭……! 도망치긴 늦었나?`,JPN:`くっ……！　もう逃げるには遅いか？`,ENG:`Krrgh...! It's too late to run...!`,TWN:`咳……！為時已晚嗎？`},stage:{bg:`NOMAD_BORDER`,slots:{L:{char_id:`VIVIEN_OPR_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`HANNA_NPC_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`HANNA_NPC_NULL_ARMED`,text:{KOREA:`으으으……`,JPN:`ううう……`,ENG:`Err...`,TWN:`呃呃呃……`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`HANNA_NPC_NULL_ARMED`,text:{KOREA:`어라? 살아 있네요?`,JPN:`あれ？　生きてますね？`,ENG:`Huh? We're alive?`,TWN:`嗯？我還沒死？`},stage:{bg:`SKY`,slots:{L:{char_id:`HANNA_NPC_NULL_ARMED`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`HANNA_NPC_NULL_ARMED`,text:{KOREA:`그런데 저희 지금 뭘 타고 있는 거죠?`,JPN:`ところで私たちが乗ってるこれって、何でしょう？`,ENG:`But what's this thing we're riding on right now?`,TWN:`不過我們現在在騎的是什麼？`},stage:{bg:`SKY`,slots:{L:{char_id:`HANNA_NPC_NULL_ARMED`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`VIVIEN_OPR_NULL_NULL`,text:{KOREA:`이건…… 병기마?`,JPN:`これは……兵器馬？`,ENG:`Isn't this... an Armored Horse?`,TWN:`這是…… 戰馬？`},stage:{bg:`SKY`,slots:{L:{char_id:`HANNA_NPC_NULL_ARMED`,face:`UNIT_IDLE`},C:null,R:{char_id:`VIVIEN_OPR_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L28_1`,type:`dialog`,speaker:`HANNA_NPC_NULL_ARMED`,text:{KOREA:`꺄아아! 큰 녀석이 계속 쫓아오고 있어요!`,JPN:`きゃああ！　大きいやつがまだ追ってきてます！`,ENG:`Kyaah! The giant C.O. is still chasing after us!`,TWN:`呃啊啊！大塊頭一直追上來！`},stage:{bg:`NOMAD_BORDER`,slots:{L:{char_id:`HANNA_NPC_NULL_ARMED`,face:`UNIT_IDLE`},C:null,R:{char_id:`VIVIEN_OPR_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L32_1`,type:`dialog`,speaker:`PITER_BORDER_NULL_ARMED`,text:{KOREA:`허밋이 장교 분을 무사히 구출했습니다! 협곡 지대로 유인 중!`,JPN:`ハーミットが将校を無事救出しました！　峡谷地帯へ誘導中！`,ENG:`Hermit has safely rescued the officer! Currently luring the enemy into the valley!`,TWN:`赫米特已經順利救出軍官！正將侵蝕體引至峽谷地帶！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`PITER_BORDER_NULL_ARMED`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};